# -*- coding: utf-8 -*-
ROWS = [
(195,"单选","权益结算的股份支付，在等待期内每个资产负债表日确认成本费用，其计量基础是（）。",["A"],"权益结算的股份支付以授予日权益工具的公允价值为基础，按等待期内职工提供服务的累计金额确认成本费用。选A。",[("A","授予日权益工具的公允价值"),("B","行权日权益工具的公允价值"),("C","每个资产负债表日权益工具的公允价值"),("D","权益工具的内在价值")]),
(195,"判断","现金结算的股份支付，应当在每个资产负债表日按权益工具的公允价值重新计量，公允价值变动计入当期损益。（）",["对"],"现金结算的股份支付以每个资产负债表日公允价值计量，变动计入公允价值变动损益。表述正确。"),
(196,"单选","下列可行权条件中，属于市场条件的是（）。",["C"],"市场条件指与权益工具市场价格相关的条件，如股价达到一定水平；连续服务、净利润增长率、销售量增长属服务期限条件或非市场业绩条件。选C。",[("A","连续服务满3年"),("B","净利润增长率不低于10%"),("C","公司股价达到20元/股"),("D","销售量增长20%")]),
(196,"判断","企业取消或结算股份支付的，应当作为加速行权处理，立即确认剩余等待期内应确认的费用。（）",["对"],"取消或结算股份支付作为加速行权处理，立即确认剩余费用。表述正确。"),
(198,"多选","下列各项中，属于借款费用的有（）。",["A","B","C"],"借款费用包括借款利息、折价或溢价的摊销、辅助费用、因外币借款发生的汇兑差额。股票发行费等权益性融资费用不属于借款费用。选A、B、C。",[("A","借款利息"),("B","折价或溢价的摊销"),("C","因外币借款发生的汇兑差额"),("D","发行股票发生的费用")]),
(198,"判断","企业发行股票等权益性融资发生的费用，属于借款费用。（）",["错"],"权益性融资费用不属于借款费用。表述错误。"),
(199,"单选","为购建或者生产符合资本化条件的资产而专门借入的款项是（）。",["A"],"专门借款是为购建或生产符合资本化条件资产而专门借入的款项；一般借款是除专门借款外的其他借款。选A。",[("A","专门借款"),("B","一般借款"),("C","短期借款"),("D","信用借款")]),
(199,"判断","专门借款在资本化期间取得的闲置资金收益，应当冲减借款费用的资本化金额。（）",["对"],"专门借款闲置资金收益冲减资本化金额；一般借款闲置资金收益不冲减。表述正确。"),
(200,"多选","借款费用开始资本化应当同时满足的条件有（）。",["A","B","C"],"开始资本化需同时满足：资产支出已经发生、借款费用已经发生、为使资产达到预定可使用或可销售状态所必要的购建或生产活动已经开始。取得竣工验收报告不是开始资本化的条件。选A、B、C。",[("A","资产支出已经发生"),("B","借款费用已经发生"),("C","为使资产达到预定可使用或可销售状态所必要的购建或生产活动已经开始"),("D","已取得竣工验收报告")]),
(200,"判断","企业仅取得了银行贷款但尚未动工建造资产，即可开始将借款费用资本化。（）",["错"],"还需必要的购建或生产活动已经开始且资产支出已经发生。仅取得贷款未动工不满足。表述错误。"),
(202,"单选","借款费用停止资本化的时点是（）。",["C"],"资产达到预定可使用或可销售状态时停止资本化，不以办理竣工决算、取得产权证为标志。选C。",[("A","办理竣工决算时"),("B","取得产权证书时"),("C","资产达到预定可使用或可销售状态时"),("D","资产实际投入使用时")]),
(202,"判断","购建的固定资产达到预定可使用状态后发生的借款费用，应当计入当期损益。（）",["对"],"停止资本化后发生的借款费用一律费用化。表述正确。"),
(204,"单选","专门借款发生的辅助费用，在所购建资产达到预定可使用状态前发生的，应当（）。",["B"],"专门借款辅助费用在资产达到预定状态前发生的予以资本化，达到状态后发生的计入当期损益。选B。",[("A","全部费用化"),("B","予以资本化"),("C","冲减递延收益"),("D","计入营业外支出")]),
(204,"判断","一般借款发生的辅助费用，无论何时发生，均于发生时计入当期损益。（）",["对"],"一般借款辅助费用一律费用化。表述正确。"),
(206,"多选","下列各项中，属于或有事项特征的有（）。",["A","B","C"],"或有事项特征：由过去的交易或事项形成、结果具有不确定性、结果须由未来事项的发生或不发生予以证实（不能由企业单方面控制）。选A、B、C。",[("A","由过去的交易或事项形成"),("B","结果具有不确定性"),("C","结果须由未来事项的发生或不发生予以证实"),("D","结果由企业单方面控制")]),
(206,"判断","企业未来计划进行的经营行为（如拟签订的合同）属于或有事项。（）",["错"],"或有事项须由过去交易或事项形成，未来计划的经营行为不属于或有事项。表述错误。"),
(210,"单选","资产负债表日，有确凿证据表明预计负债的账面价值不能真实反映当前最佳估计数的，企业应当（）。",["B"],"资产负债表日复核预计负债账面价值，按当前最佳估计数调整，差额计入当期损益，不追溯前期。选B。",[("A","不予调整"),("B","按当前最佳估计数进行调整"),("C","追溯调整前期"),("D","转销全部余额")]),
(210,"判断","“预计负债”科目不应当出现借方余额。（）",["对"],"预计负债是负债类科目，不应出现借方余额。表述正确。"),
(214,"单选","下列各项中，属于收入的是（）。",["A"],"收入是企业日常活动中形成的、导致所有者权益增加、与所有者投入资本无关的经济利益总流入，如销售商品收入。处置固定资产利得、投资收益、捐赠利得不属于收入。选A。",[("A","销售商品取得的收入"),("B","处置固定资产的利得"),("C","取得的投资收益"),("D","接受捐赠利得")]),
(214,"判断","收入是企业在日常活动中形成的、会导致所有者权益增加的、与所有者投入资本无关的经济利益的总流入。（）",["对"],"该表述即收入的定义。表述正确。"),
(215,"单选","按照新收入准则，企业确认收入的时点是（）。",["B"],"新收入准则以客户取得相关商品（或服务）控制权作为收入确认时点，不再以风险报酬转移为唯一标准。选B。",[("A","风险报酬转移时"),("B","客户取得相关商品（或服务）控制权时"),("C","收到货款时"),("D","开具发票时")]),
(215,"判断","新收入准则强调以“控制权转移”作为收入确认的标准。（）",["对"],"新准则强调控制权转移而非风险报酬转移。表述正确。"),
(217,"单选","合同中企业向客户转让可明确区分商品或服务的承诺，称为（）。",["C"],"履约义务是合同中向客户转让可明确区分商品或服务的承诺；构成最小单元的为单项履约义务。选C。",[("A","交易价格"),("B","合同负债"),("C","单项履约义务"),("D","合同资产")]),
(217,"判断","某项商品或服务“可明确区分”，是其构成单项履约义务的条件之一。（）",["对"],"可明确区分是识别单项履约义务的前提条件。表述正确。"),
(220,"单选","企业将交易价格分摊至各单项履约义务，应当按照（）进行分摊。",["B"],"交易价格按各单项履约义务单独售价的相对比例分摊。选B。",[("A","各履约义务成本的比例"),("B","各单项履约义务单独售价的相对比例"),("C","平均分摊"),("D","合同约定的顺序")]),
(220,"判断","合同折扣一般应当分摊至合同中所有单项履约义务，但有证据表明折扣仅与其中一项或多项相关的除外。（）",["对"],"合同折扣原则上分摊至所有履约义务，明确指定的除外。表述正确。"),
(222,"单选","企业为取得合同发生的增量成本，预期能够收回的，应当（）。",["B"],"为取得合同发生的增量成本且预期能收回的，确认为一项资产（合同取得成本）。选B。",[("A","计入当期损益"),("B","确认为一项资产"),("C","冲减收入"),("D","计入管理费用")]),
(222,"判断","企业无论是否取得合同都会发生的差旅费等成本，应当于发生时计入当期损益。（）",["对"],"非增量成本不符合资本化条件，于发生时计入当期损益。表述正确。"),
(223,"单选","合同提前终止时，合同取得成本形成的资产尚未摊销的余额应当（）。",["B"],"合同提前终止，合同取得成本资产尚未摊销余额一次性计入当期损益。选B。",[("A","继续摊销"),("B","一次性计入当期损益"),("C","转入下期"),("D","冲减收入")]),
(223,"判断","合同履约成本和合同取得成本，应当按照与其相关的商品收入确认相同的基础进行摊销。（）",["对"],"合同成本资产按相关收入确认的相同基础摊销。表述正确。"),
(225,"单选","企业向客户提供的、客户可以单独购买的延长保修期服务，应当（）。",["B"],"提供超出法定质保的、可单独购买的服务质保，构成单项履约义务，需单独分摊交易价格并分期确认收入。选B。",[("A","计入销售费用"),("B","作为单项履约义务单独分摊交易价格"),("C","冲减收入"),("D","计入营业外支出")]),
(225,"判断","法定质量保证（保证商品符合既定标准）不构成单项履约义务，相关支出计入销售费用。（）",["对"],"法定质保不构成单项履约义务，支出计入销售费用。表述正确。"),
(226,"单选","企业在向客户转让商品前能够控制该商品的，应当作为（）。",["B"],"转让商品前能够控制该商品的为主要责任人，按总额确认收入；不能控制的为代理人，按净额确认收入。选B。",[("A","代理人，按净额确认收入"),("B","主要责任人，按总额确认收入"),("C","代理人，按总额确认收入"),("D","主要责任人，按净额确认收入")]),
(226,"判断","企业为代理人的，应当按照预期有权收取的佣金或手续费净额确认收入。（）",["对"],"代理人按净额（佣金或手续费）确认收入。表述正确。"),
(227,"判断","客户额外购买选择权向其提供了一项重大权利的，企业应当将该选择权作为单项履约义务。（）",["对"],"提供重大权利的额外购买选择权构成单项履约义务。表述正确。"),
(227,"单选","客户额外购买选择权构成重大权利的，分摊至该选择权的对价应当（）。",["B"],"分摊至选择权的对价确认为合同负债，待客户行使权利或选择权失效时转入收入。选B。",[("A","立即确认为收入"),("B","确认为合同负债，待客户行权或失效时转入收入"),("C","冲减成本"),("D","计入营业外收入")]),
(229,"单选","售后回购中，企业按照固定价格（或本金加利息）回购商品的，该交易实质上属于（）。",["B"],"按固定价格或本金加利息回购，表明企业承担融资义务，属于融资交易，不确认收入。选B。",[("A","销售交易，确认收入"),("B","融资交易，不确认收入"),("C","租赁交易"),("D","捐赠")]),
(229,"判断","售后回购属于融资安排的，企业发出商品时不确认收入、不结转成本，收到的款项确认为负债。（）",["对"],"融资性售后回购发出商品不确认收入，收款确认为负债。表述正确。"),
(230,"单选","客户预付款项后未行使全部权利（如过期作废的预付卡余额），企业（）。",["B"],"不得在收款时全额确认收入；企业应按客户行使权利的模式比例（结合预期失效情况）确认收入。选B。",[("A","收款时全额确认收入"),("B","按客户行使权利的模式比例确认收入"),("C","永久挂账合同负债"),("D","一律退还客户")]),
(230,"判断","客户预付款项购买商品后未行使的权利（如过期作废的预付卡余额），企业不得在收款时全额确认收入。（）",["对"],"预收款项应先计入合同负债，不得收款时全额确认收入。表述正确。"),
(231,"单选","企业收取的无需退回的初始费，与向客户转让已承诺商品或服务相关的，应当（）。",["B"],"与已承诺商品或服务相关的无需退回初始费，作为交易价格组成部分，在相关商品或服务转让时确认收入。选B。",[("A","收取时全额确认收入"),("B","作为交易价格组成部分，在相关商品或服务转让时确认收入"),("C","计入资本公积"),("D","永久不予确认")]),
(231,"判断","企业收取的无需退回的初始费，凡与未来将转让的商品或服务相关的，应当在提供该商品或服务时确认收入。（）",["对"],"与未来履约义务相关的初始费随义务履行确认收入。表述正确。"),
(233,"单选","政府补助按照其是否与资产相关，分为（）。",["A"],"政府补助分为与资产相关的政府补助和与收益相关的政府补助。选A。",[("A","与资产相关的政府补助和与收益相关的政府补助"),("B","总额法补助和净额法补助"),("C","货币性补助和非货币性补助"),("D","无偿补助和有偿补助")]),
(233,"判断","同一政府补助文件同时包含与资产相关和与收益相关用途的，应当按照合理的方法予以拆分。（）",["对"],"含多项用途的补助应合理拆分，无法区分的整体作为与收益相关处理。表述正确。"),
(237,"单选","对于同时包含与资产相关和与收益相关部分的综合性政府补助，企业应当（）。",["C"],"综合性政府补助应按合理方法拆分后分别处理；难以拆分的整体作为与收益相关处理。选C。",[("A","整体作为与资产相关处理"),("B","整体作为与收益相关处理"),("C","按合理方法拆分后分别处理"),("D","不予确认")]),
(237,"判断","同时包含与资产相关和与收益相关部分的综合性政府补助，难以区分的，应当整体归类为与收益相关的政府补助。（）",["对"],"难以区分的综合性补助整体作为与收益相关处理。表述正确。"),
(239,"单选","在非货币性资产交换中，认定为非货币性资产交换的补价比例条件是（）。",["A"],"补价占整个资产交换金额的比例低于25%的，认定为非货币性资产交换；高于（含等于）25%的为货币性交易。选A。",[("A","补价占整个资产交换金额的比例低于25%"),("B","补价占比低于10%"),("C","补价占比低于50%"),("D","补价占比低于5%")]),
(239,"判断","应收账款、应收票据属于货币性资产。（）",["对"],"货币性资产指货币资金及将以固定或可确定金额收取的资产，应收账款、应收票据属于货币性资产。表述正确。"),
(243,"单选","不涉及补价的非货币性资产交换，采用公允价值计量的，换入资产的成本为（）。",["B"],"公允价值模式下，换入资产成本=换出资产公允价值+相关税费；换出资产公允价值与账面价值的差额计入当期损益。选B。",[("A","换出资产账面价值加相关税费"),("B","换出资产公允价值加相关税费"),("C","换入资产的账面价值"),("D","双方协商确定的价格")]),
(243,"判断","非货币性资产交换采用账面价值计量的，不确认损益。（）",["对"],"账面价值模式下，换入资产成本按换出资产账面价值加相关税费确定，不确认损益。表述正确。"),
]
